export const books: BibleBook[] = [
  { id: 1, name: "Genesis", chapters: 50, author: "Moses", testament: "old", genre: "law", genreLabel: "The Law", description: "The book of beginnings: creation, the fall of humanity, the flood, and God's covenant with Abraham. Traces the origins of Israel through the patriarchs Abraham, Isaac, Jacob, and Joseph.", keyVerse: "In the beginning God created the heavens and the earth.. Genesis 1:1", tags: ["Creation", "Abraham", "Joseph", "Covenant"], studyGuide: { keyPassages: ["Genesis 1-2. The creation account", "Genesis 3. The fall of humanity", "Genesis 12:1-3. God's covenant with Abraham", "Genesis 22. The sacrifice of Isaac", "Genesis 37-50. The Joseph narrative"], connections: "Genesis lays the foundation for every theme in Scripture. The promise to Abraham (12:1-3) threads through the entire Bible to Galatians 3. The 'seed of the woman' in 3:15 is the first Messianic prophecy, fulfilled in Christ. Joseph's story foreshadows Jesus. rejected by his brothers, exalted to save many.", bestFor: "Understanding the Bible's big story, God's character, and the roots of the gospel" } },
  { id: 2, name: "Exodus", chapters: 40, author: "Moses", testament: "old", genre: "law", genreLabel: "The Law", description: "Israel is freed from slavery in Egypt through dramatic plagues and the parting of the Red Sea. God gives the Ten Commandments at Sinai and instructs Moses to build the tabernacle. a place where God dwells among His people.", keyVerse: "Let my people go, so that they may worship me.. Exodus 8:1", tags: ["Moses", "Plagues", "Ten Commandments", "Freedom"], studyGuide: { keyPassages: ["Exodus 3. The burning bush and God's name revealed", "Exodus 12. The Passover instituted", "Exodus 14. Crossing the Red Sea", "Exodus 20. The Ten Commandments", "Exodus 33-34. Moses sees God's glory"], connections: "The Passover lamb in Exodus 12 directly foreshadows Christ (1 Corinthians 5:7). The tabernacle points to Jesus 'tabernacling' among us (John 1:14). The exodus itself becomes the Bible's defining metaphor for salvation. liberation from bondage into covenant relationship.", bestFor: "Seeing God as liberator, understanding worship and covenant, the roots of communion" } },
  { id: 3, name: "Leviticus", chapters: 27, author: "Moses", testament: "old", genre: "law", genreLabel: "The Law", description: "The handbook for priests and worship: detailed laws on sacrifice, cleanness, and holiness. Often overlooked but central to understanding how a holy God can dwell with imperfect people.", keyVerse: "Be holy because I, the Lord your God, am holy.. Leviticus 19:2", tags: ["Holiness", "Sacrifice", "Priesthood"], studyGuide: { keyPassages: ["Leviticus 1-7. The five offerings and what they mean", "Leviticus 16. The Day of Atonement", "Leviticus 19. Practical holiness ('love your neighbour')", "Leviticus 23. The feasts of the Lord", "Leviticus 25. The Year of Jubilee"], connections: "Hebrews 9-10 explains how every sacrifice in Leviticus pointed to Christ's once-for-all offering. The Day of Atonement (ch. 16) is the clearest Old Testament picture of substitutionary atonement. Jesus quotes Leviticus 19:18 as the second greatest commandment (Matthew 22:39).", bestFor: "Understanding atonement, holiness, and why the cross was necessary" } },
  { id: 4, name: "Numbers", chapters: 36, author: "Moses", testament: "old", genre: "law", genreLabel: "The Law", description: "Israel's 40-year wilderness journey, marked by census-taking, rebellion, grumbling, and God's extraordinary patience. A generation misses the promised land through unbelief, but God's promises endure.", tags: ["Wilderness", "Census", "Rebellion"], studyGuide: { keyPassages: ["Numbers 6:24-26. The Aaronic blessing", "Numbers 13-14. Spying out the land and Israel's refusal to enter", "Numbers 20. Moses strikes the rock", "Numbers 21:4-9. The bronze serpent", "Numbers 22-24. Balaam's donkey and blessings"], connections: "Jesus references the bronze serpent as a picture of His crucifixion (John 3:14). Paul uses Israel's wilderness failures as a warning for believers (1 Corinthians 10:1-13). Hebrews 3-4 draws heavily on the unbelief at Kadesh (ch. 14) to urge faithfulness.", bestFor: "Learning from failure, understanding God's patience, the danger of unbelief" } },
  { id: 5, name: "Deuteronomy", chapters: 34, author: "Moses", testament: "old", genre: "law", genreLabel: "The Law", description: "Moses' farewell speeches to Israel on the edge of the promised land. a passionate call to remember God's faithfulness and choose obedience.", keyVerse: "Love the Lord your God with all your heart and with all your soul and with all your strength.. Deuteronomy 6:5", tags: ["Covenant renewal", "Obedience", "Moses' farewell"], studyGuide: { keyPassages: ["Deuteronomy 6:4-9. The Shema, Israel's creed", "Deuteronomy 8. Remember and don't forget", "Deuteronomy 18:15-19. A prophet like Moses", "Deuteronomy 28. Blessings and curses", "Deuteronomy 34. The death of Moses"], connections: "Jesus quotes Deuteronomy three times to defeat Satan's temptations (Matthew 4). He calls Deuteronomy 6:5 the greatest commandment. The 'prophet like Moses' (18:15) is fulfilled in Christ (Acts 3:22).", bestFor: "Spiritual renewal, parenting and passing on faith, understanding Jesus' Bible" } },
  { id: 6, name: "Joshua", chapters: 24, author: "Joshua", testament: "old", genre: "history", genreLabel: "History", description: "The conquest and settlement of the promised land under Joshua's leadership. After 40 years of wandering, God fulfils His promise. but Israel must fight for it in faith.", keyVerse: "Be strong and courageous. Do not be afraid; do not be discouraged, for the Lord your God will be with you wherever you go.. Joshua 1:9", tags: ["Conquest", "Jericho", "Promise fulfilled"], studyGuide: { keyPassages: ["Joshua 1. God commissions Joshua", "Joshua 2. Rahab and the spies", "Joshua 6. The fall of Jericho", "Joshua 7. Achan's sin and its consequences", "Joshua 24:14-15. 'Choose this day whom you will serve'"], connections: "Joshua's name is the Hebrew form of 'Jesus'. both lead God's people into the promised inheritance. Rahab appears in Jesus' genealogy (Matthew 1:5) and the hall of faith (Hebrews 11:31).", bestFor: "Stepping into God's promises, courage in leadership, the cost of compromise" } },
  { id: 7, name: "Judges", chapters: 21, author: "Unknown", testament: "old", genre: "history", genreLabel: "History", description: "A dark, cyclical period of Israel's history: the people rebel, God allows oppression, they cry out, God raises a deliverer. and then they rebel again.", keyVerse: "In those days Israel had no king; everyone did as they saw fit.. Judges 21:25", tags: ["Gideon", "Samson", "Deborah", "Cycle of sin"], studyGuide: { keyPassages: ["Judges 2:11-23. The cycle of rebellion explained", "Judges 4-5. Deborah and Barak", "Judges 6-7. Gideon's 300", "Judges 13-16. Samson's rise and fall", "Judges 19-21. The horror at Gibeah"], connections: "Judges shows why Israel needed a true king. setting up the monarchy in 1 Samuel and ultimately pointing to Christ the King. Hebrews 11:32-34 honours several judges by faith.", bestFor: "Understanding consequences of moral drift, the need for godly leadership, cultural parallels to today" } },
  { id: 8, name: "Ruth", chapters: 4, author: "Unknown", testament: "old", genre: "history", genreLabel: "History", description: "A beautiful short story set during the dark period of the judges. A Moabite widow's loyalty to her mother-in-law leads her to Bethlehem, where she finds redemption and love. and enters the lineage of King David and Jesus.", keyVerse: "Where you go I will go, and where you stay I will stay. Your people will be my people and your God my God.. Ruth 1:16", tags: ["Loyalty", "Redemption", "Love story"], studyGuide: { keyPassages: ["Ruth 1:16-17. Ruth's vow of loyalty", "Ruth 2. Gleaning in Boaz's field", "Ruth 3. The threshing floor", "Ruth 4:13-17. Marriage, baby Obed, and David's line"], connections: "Ruth is a Gentile woman in Jesus' genealogy (Matthew 1:5), showing God's plan always included the nations. Boaz is a 'kinsman-redeemer', a powerful picture of what Christ does for us.", bestFor: "God's providence in ordinary life, inclusion and grace, romantic love as spiritual metaphor" } },
  { id: 9, name: "1 Samuel", chapters: 31, author: "Unknown", testament: "old", genre: "history", genreLabel: "History", description: "The transition from judges to monarchy. Samuel anoints Saul as Israel's first king, but Saul's disobedience leads to his downfall while David, a shepherd boy, rises as God's chosen king.", tags: ["David & Goliath", "Saul", "Kingship"], studyGuide: { keyPassages: ["1 Samuel 3. God calls young Samuel", "1 Samuel 8. Israel demands a king", "1 Samuel 16. David anointed ('the Lord looks at the heart')", "1 Samuel 17. David and Goliath", "1 Samuel 18-20. David and Jonathan's friendship"], connections: "David is the most important Old Testament 'type' of Christ. anointed but not yet enthroned, loved and persecuted. Hannah's prayer (ch. 2) is echoed by Mary's Magnificat (Luke 1:46-55).", bestFor: "God's surprising choices, leadership character, friendship, trusting God's timing" } },
  { id: 10, name: "2 Samuel", chapters: 24, author: "Unknown", testament: "old", genre: "history", genreLabel: "History", description: "David's reign. its brilliant highs and devastating lows. He conquers Jerusalem, brings the ark home, and receives God's everlasting covenant, but his affair with Bathsheba triggers a chain of family disaster.", tags: ["David's reign", "Bathsheba", "Absalom"], studyGuide: { keyPassages: ["2 Samuel 6. David dances before the ark", "2 Samuel 7. God's covenant with David (the Davidic covenant)", "2 Samuel 11-12. David, Bathsheba, and Nathan's confrontation", "2 Samuel 18. Absalom's death", "2 Samuel 22. David's song of praise"], connections: "The Davidic covenant (ch. 7) is the backbone of Messianic expectation. Jesus is the 'Son of David' who reigns forever (Luke 1:32-33). David's sin and repentance produced Psalm 51.", bestFor: "Leadership and accountability, consequences of sin, worship, God's unconditional promises" } },
  { id: 11, name: "1 Kings", chapters: 22, author: "Unknown", testament: "old", genre: "history", genreLabel: "History", description: "Solomon's golden age and the temple's construction, followed by the kingdom's tragic split into north (Israel) and south (Judah). Introduces the great prophet Elijah.", tags: ["Solomon", "Temple", "Elijah", "Division"], studyGuide: { keyPassages: ["1 Kings 3. Solomon asks for wisdom", "1 Kings 8. Solomon's temple dedication prayer", "1 Kings 12. The kingdom divides", "1 Kings 18. Elijah on Mount Carmel", "1 Kings 19. Elijah flees and God whispers"], connections: "Solomon's temple is superseded by Jesus ('something greater than the temple is here', Matthew 12:6). Elijah becomes the model prophet, appearing at the Transfiguration with Moses (Mark 9:4).", bestFor: "True vs false worship, burnout and God's gentle restoration, the danger of compromise" } },
  { id: 12, name: "2 Kings", chapters: 25, author: "Unknown", testament: "old", genre: "history", genreLabel: "History", description: "The long decline and fall of both kingdoms. The northern kingdom falls to Assyria in 722 BC, and the southern kingdom to Babylon in 586 BC. Elisha performs miracles, and a few good kings bring revival, but the exile comes.", tags: ["Elisha", "Exile", "Decline"], studyGuide: { keyPassages: ["2 Kings 2. Elijah taken up, Elisha receives double portion", "2 Kings 5. Naaman healed of leprosy", "2 Kings 17. The fall of the northern kingdom", "2 Kings 22-23. Josiah's reforms after finding the Law", "2 Kings 25. The fall of Jerusalem"], connections: "Jesus references Naaman and the widow of Zarephath (Luke 4:25-27) to show God's grace extends to outsiders. The exile shapes Judaism and sets the stage for the world Jesus was born into.", bestFor: "Consequences of national sin, revival and reform, God's faithfulness even in judgement" } },
  { id: 13, name: "1 Chronicles", chapters: 29, author: "Ezra", testament: "old", genre: "history", genreLabel: "History", description: "A retelling of Israel's history from Adam to David, written for the post-exile community. Focuses on David's preparations for the temple and the importance of worship.", tags: ["Genealogies", "David", "Worship"], studyGuide: { keyPassages: ["1 Chronicles 4:10. The prayer of Jabez", "1 Chronicles 16:8-36. David's psalm of thanksgiving", "1 Chronicles 17. The Davidic covenant retold", "1 Chronicles 22. David's charge to Solomon", "1 Chronicles 29:10-20. David's prayer of praise for the temple offerings"], connections: "The genealogies in chapters 1-9 provide the backbone for Matthew's genealogy of Jesus. David's worship arrangements influence synagogue and church worship patterns.", bestFor: "Worship, legacy and generational faithfulness, finding your place in God's story" } },
  { id: 14, name: "2 Chronicles", chapters: 36, author: "Ezra", testament: "old", genre: "history", genreLabel: "History", description: "From Solomon's temple to its destruction. the history of Judah's kings, focusing on those who sought God and those who abandoned Him.", keyVerse: "If my people, who are called by my name, will humble themselves and pray and seek my face and turn from their wicked ways, then I will hear from heaven.. 2 Chronicles 7:14", tags: ["Temple", "Kings", "Repentance"], studyGuide: { keyPassages: ["2 Chronicles 1. Solomon asks for wisdom", "2 Chronicles 7:14. God's promise of healing", "2 Chronicles 20. Jehoshaphat's prayer and the battle won by worship", "2 Chronicles 34. Josiah's revival", "2 Chronicles 36:22-23. Cyrus' decree to rebuild"], connections: "2 Chronicles 7:14 is one of the most quoted verses in prayer movements worldwide. Jehoshaphat's 'worship as warfare' (ch. 20) becomes a spiritual warfare pattern in the New Testament.", bestFor: "National and personal repentance, worship as spiritual warfare, revival" } },
  { id: 15, name: "Ezra", chapters: 10, author: "Ezra", testament: "old", genre: "history", genreLabel: "History", description: "The first wave of Jewish exiles returns from Babylon to rebuild the temple. Ezra, a scribe devoted to God's law, leads a second wave and confronts threats to Israel's identity.", tags: ["Return", "Rebuilding", "Reform"], studyGuide: { keyPassages: ["Ezra 1. Cyrus' decree fulfils Jeremiah's prophecy", "Ezra 3. Foundation laid, old men weep", "Ezra 7:10. Ezra's devotion to the Word", "Ezra 9. Ezra's prayer of confession"], connections: "The return from exile is the 'second exodus' the prophets promised (Isaiah 40-55). Ezra's devotion to Scripture (7:10) models the pattern Jesus and the apostles followed.", bestFor: "Spiritual renewal through Scripture, starting over after failure, the power of confession" } },
  { id: 16, name: "Nehemiah", chapters: 13, author: "Nehemiah", testament: "old", genre: "history", genreLabel: "History", description: "A cupbearer to the Persian king leaves comfort to rebuild Jerusalem's walls in just 52 days. despite fierce opposition. A masterclass in prayer-fuelled, practical leadership.", tags: ["Leadership", "Walls rebuilt", "Prayer"], studyGuide: { keyPassages: ["Nehemiah 1. Nehemiah's prayer of grief and faith", "Nehemiah 2:1-8. Nehemiah before the king", "Nehemiah 4. Building with a sword in one hand", "Nehemiah 6:15-16. The wall completed in 52 days", "Nehemiah 8. Ezra reads the Law and the people weep"], connections: "Nehemiah's 'arrow prayer' approach (2:4) models integrating prayer into everyday moments. His leadership principles are timeless. vision, prayer, perseverance, delegation.", bestFor: "Leadership, perseverance under opposition, integrating prayer with action" } },
  { id: 17, name: "Esther", chapters: 10, author: "Unknown", testament: "old", genre: "history", genreLabel: "History", description: "God's name never appears in this book, yet His providence drives every scene. A Jewish orphan becomes queen of Persia and risks her life to save her people from genocide.", keyVerse: "And who knows but that you have come to your royal position for such a time as this?. Esther 4:14", tags: ["Providence", "Courage", "Deliverance"], studyGuide: { keyPassages: ["Esther 2:17. Esther becomes queen", "Esther 3. Haman's plot to destroy the Jews", "Esther 4:14. 'For such a time as this'", "Esther 7. Haman exposed and the tables turn", "Esther 9. The feast of Purim established"], connections: "Esther shows God working behind the scenes even when He seems absent. The reversal theme echoes throughout Scripture (Proverbs 26:27, Galatians 6:7). Purim is still celebrated by Jews today.", bestFor: "Trusting God when He seems silent, courage, understanding divine providence" } },
  { id: 18, name: "Job", chapters: 42, author: "Unknown", testament: "old", genre: "poetry", genreLabel: "Poetry & Wisdom", description: "A righteous man loses everything. children, wealth, health. and his friends insist he must have sinned. Job demands answers from God, and God responds with breathtaking questions that reframe everything.", tags: ["Suffering", "Sovereignty", "Faith tested"], studyGuide: { keyPassages: ["Job 1-2. The heavenly courtroom and Job's losses", "Job 13:15. 'Though he slay me, yet will I hope in him'", "Job 19:25-27. 'I know that my redeemer lives'", "Job 38-41. God speaks from the whirlwind", "Job 42. Restoration and double blessing"], connections: "Job is referenced by James (5:11) as a model of perseverance. The 'redeemer' in 19:25 points to Christ. Jesus, the truly innocent sufferer, fulfils what Job only foreshadowed.", bestFor: "Suffering and doubt, when life doesn't make sense, the limits of human wisdom" } },
  { id: 19, name: "Psalms", chapters: 150, author: "David & others", testament: "old", genre: "poetry", genreLabel: "Poetry & Wisdom", description: "The Bible's songbook and prayer book. 150 poems covering every human emotion: praise, lament, anger, joy, grief, wonder, and hope. The most quoted Old Testament book in the New Testament.", keyVerse: "The Lord is my shepherd, I lack nothing.. Psalm 23:1", tags: ["Worship", "Lament", "Praise", "Prayer"], studyGuide: { keyPassages: ["Psalm 1. The two ways of life", "Psalm 22. The crucifixion psalm (quoted by Jesus on the cross)", "Psalm 23. The Lord is my shepherd", "Psalm 51. David's prayer of repentance", "Psalm 139. God knows me completely"], connections: "Jesus quoted Psalms more than any other book. Psalm 22 describes the crucifixion in stunning detail a thousand years before it happened. Psalm 110 is the most quoted OT passage in the NT.", bestFor: "Prayer life, emotional honesty before God, personal worship, processing grief" } },
  { id: 20, name: "Proverbs", chapters: 31, author: "Solomon", testament: "old", genre: "poetry", genreLabel: "Poetry & Wisdom", description: "Pithy, practical wisdom for everyday life. money, speech, relationships, work, character. Not promises but principles: wisdom is a skill for living, and it starts with fearing the Lord.", keyVerse: "The fear of the Lord is the beginning of wisdom, and knowledge of the Holy One is understanding.. Proverbs 9:10", tags: ["Wisdom", "Practical", "Daily life"], studyGuide: { keyPassages: ["Proverbs 1:7. The fear of the Lord is the beginning of knowledge", "Proverbs 3:5-6. Trust in the Lord with all your heart", "Proverbs 8. Wisdom personified (Christ foreshadowed)", "Proverbs 15:1. A gentle answer turns away wrath", "Proverbs 31. The excellent wife (and a picture of wisdom lived out)"], connections: "Wisdom personified in Proverbs 8 is connected to Christ by Paul (1 Corinthians 1:30) and echoes in John 1. James's letter reads like a New Testament version of Proverbs.", bestFor: "Daily decision-making, character formation, practical Christian living" } },
  { id: 21, name: "Ecclesiastes", chapters: 12, author: "Solomon", testament: "old", genre: "poetry", genreLabel: "Poetry & Wisdom", description: "A searingly honest exploration of life's meaning. The 'Teacher' has tried everything. wealth, pleasure, work, knowledge. and declares it all 'meaningless' apart from God.", tags: ["Meaning of life", "Vanity", "Purpose"], studyGuide: { keyPassages: ["Ecclesiastes 1:1-11. 'Meaningless! Meaningless!'", "Ecclesiastes 3:1-8. A time for everything", "Ecclesiastes 4:9-12. Two are better than one", "Ecclesiastes 7:1-14. Wisdom for hard times", "Ecclesiastes 12:13-14. The conclusion: fear God and keep His commandments"], connections: "Ecclesiastes asks the questions that Jesus answers. The 'meaninglessness' of life under the sun finds its resolution in Christ who gives eternal purpose (John 10:10).", bestFor: "Existential questions, finding purpose, engaging sceptics, midlife reflection" } },
  { id: 22, name: "Song of Solomon", chapters: 8, author: "Solomon", testament: "old", genre: "poetry", genreLabel: "Poetry & Wisdom", description: "A passionate celebration of romantic love and physical intimacy between a bride and groom. Read literally, it affirms the goodness of marital love. Read allegorically, it pictures God's passionate love for His people.", tags: ["Love", "Romance", "Intimacy"], studyGuide: { keyPassages: ["Song of Solomon 1:2-4. The opening of desire", "Song of Solomon 2:10-13. 'Arise, my love, my beautiful one'", "Song of Solomon 4:7. 'You are altogether beautiful'", "Song of Solomon 8:6-7. 'Love is strong as death'"], connections: "The Bible begins with a marriage (Genesis 2) and ends with one (Revelation 19). The bridal metaphor runs from Hosea through Isaiah to Ephesians 5 and Revelation 21.", bestFor: "Marriage enrichment, understanding biblical sexuality, God's passionate love" } },
  { id: 23, name: "Isaiah", chapters: 66, author: "Isaiah", testament: "old", genre: "major-prophets", genreLabel: "Major Prophets", description: "Called the 'fifth Gospel' for its stunning Messianic prophecies. Isaiah warns of judgement, comforts with hope, and paints the clearest Old Testament portrait of Christ. the suffering servant who bears our sins.", keyVerse: "For to us a child is born, to us a son is given, and the government will be on his shoulders.. Isaiah 9:6", tags: ["Messiah", "Judgement", "Comfort", "Hope"], studyGuide: { keyPassages: ["Isaiah 6. Isaiah's vision of God in the temple", "Isaiah 9:6-7. A child is born (Christmas prophecy)", "Isaiah 40:1-31. 'Comfort, comfort my people'", "Isaiah 53. The suffering servant", "Isaiah 61:1-3. Good news to the poor (Jesus' mission statement)"], connections: "Isaiah 53 is the most detailed prophecy of the cross. written 700 years before Jesus. Jesus reads Isaiah 61 in the synagogue and says 'Today this is fulfilled' (Luke 4:18-21).", bestFor: "Messianic prophecy, comfort in hard times, understanding the cross, Advent" } },
  { id: 24, name: "Jeremiah", chapters: 52, author: "Jeremiah", testament: "old", genre: "major-prophets", genreLabel: "Major Prophets", description: "The 'weeping prophet' spent 40 years warning Judah of coming destruction. and was ignored, imprisoned, and mocked. Yet God promised a new covenant written on hearts, not stone.", keyVerse: "I will put my law in their minds and write it on their hearts. I will be their God, and they will be my people.. Jeremiah 31:33", tags: ["Warning", "New covenant", "Faithfulness"], studyGuide: { keyPassages: ["Jeremiah 1. God calls a reluctant young prophet", "Jeremiah 17:9. 'The heart is deceitful above all things'", "Jeremiah 18. The potter and the clay", "Jeremiah 29:11. 'Plans to prosper you' (in context!)", "Jeremiah 31:31-34. The new covenant promise"], connections: "The new covenant in Jeremiah 31 is the passage Jesus quotes at the Last Supper. Hebrews 8 quotes it at length as fulfilled in Christ.", bestFor: "Faithful perseverance, understanding the new covenant, reading familiar verses in context" } },
  { id: 25, name: "Lamentations", chapters: 5, author: "Jeremiah", testament: "old", genre: "major-prophets", genreLabel: "Major Prophets", description: "Five poems of raw grief over Jerusalem's destruction by Babylon. Yet in the centre of the darkness, he finds hope: God's mercies are new every morning.", tags: ["Grief", "Judgement", "Hope"], studyGuide: { keyPassages: ["Lamentations 1:1. 'How deserted lies the city'", "Lamentations 2:11-12. Children dying in the streets", "Lamentations 3:22-26. 'Great is thy faithfulness'", "Lamentations 3:40. 'Let us examine our ways'", "Lamentations 5:21. 'Restore us to yourself, Lord'"], connections: "Lamentations 3:22-23 inspired the hymn 'Great Is Thy Faithfulness'. Jesus weeps over Jerusalem in Luke 19:41-44, echoing Jeremiah's grief.", bestFor: "Processing grief, finding hope in darkness, honest prayer in suffering" } },
  { id: 26, name: "Ezekiel", chapters: 48, author: "Ezekiel", testament: "old", genre: "major-prophets", genreLabel: "Major Prophets", description: "Extraordinary visions from exile in Babylon: God's glory departing the temple, the valley of dry bones coming to life, a future temple where God dwells forever.", tags: ["Visions", "Exile", "Dry bones", "Restoration"], studyGuide: { keyPassages: ["Ezekiel 1. The vision of God's throne-chariot", "Ezekiel 10-11. God's glory leaves the temple", "Ezekiel 34. God as the true shepherd", "Ezekiel 37. The valley of dry bones", "Ezekiel 47:1-12. The river of life from the temple"], connections: "Jesus calls Himself the 'good shepherd' directly from Ezekiel 34. The dry bones vision pictures both Israel's restoration and spiritual resurrection (Ephesians 2:1-5). The river of life reappears in Revelation 22.", bestFor: "Hope after devastation, the Holy Spirit's power, God's plans for restoration" } },
  { id: 27, name: "Daniel", chapters: 12, author: "Daniel", testament: "old", genre: "major-prophets", genreLabel: "Major Prophets", description: "A young exile thrives in Babylon by refusing to compromise his faith. Famous stories (fiery furnace, lions' den) give way to apocalyptic visions of empires rising and falling. all under God's sovereignty.", tags: ["Faithfulness", "Prophecy", "Lions' den", "Empires"], studyGuide: { keyPassages: ["Daniel 1. Daniel's resolve not to defile himself", "Daniel 3. The fiery furnace ('even if he does not')", "Daniel 6. Daniel in the lions' den", "Daniel 7. The Son of Man vision", "Daniel 9:24-27. The seventy weeks prophecy"], connections: "Jesus' favourite self-title, 'Son of Man', comes from Daniel 7:13-14. Daniel's apocalyptic visions provide the framework for Revelation.", bestFor: "Faithfulness under pressure, living in a secular culture, understanding prophecy" } },
  { id: 28, name: "Hosea", chapters: 14, author: "Hosea", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "God commands Hosea to marry an unfaithful woman as a living parable of God's relentless love for unfaithful Israel. One of the most powerful pictures of grace in the Old Testament.", tags: ["Unfailing love", "Faithfulness"], studyGuide: { keyPassages: ["Hosea 1-3. Hosea's marriage as parable", "Hosea 2:14-23. God woos Israel back", "Hosea 6:6. 'I desire mercy, not sacrifice'", "Hosea 11:1-4. God's tender love as a father", "Hosea 14. A call to return"], connections: "Jesus quotes Hosea 6:6 twice (Matthew 9:13, 12:7). Hosea's marriage foreshadows Christ's love for the church (Ephesians 5:25-27).", bestFor: "Understanding God's relentless love, marriage and faithfulness, returning to God after failure" } },
  { id: 29, name: "Joel", chapters: 3, author: "Joel", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "A devastating locust plague becomes a window into the 'Day of the Lord'. Contains the famous promise that God will pour out His Spirit on all people.", tags: ["Day of the Lord", "Repentance", "Spirit"], studyGuide: { keyPassages: ["Joel 1:1-12. The locust plague described", "Joel 2:12-13. 'Rend your heart and not your garments'", "Joel 2:25. 'I will restore the years the locusts have eaten'", "Joel 2:28-32. The Spirit poured out on all flesh"], connections: "Peter quotes Joel 2:28-32 at Pentecost (Acts 2:16-21). Joel 2:25's promise of restoration is a lifeline for anyone who feels they've wasted years.", bestFor: "Repentance, the Holy Spirit, restoration after loss, understanding Pentecost" } },
  { id: 30, name: "Amos", chapters: 9, author: "Amos", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "A shepherd from the sticks confronts the wealthy elite of Israel's northern kingdom. Their worship is impressive, but their treatment of the poor makes God sick.", keyVerse: "But let justice roll on like a river, righteousness like a never-failing stream!. Amos 5:24", tags: ["Justice", "Social ethics", "Warning"], studyGuide: { keyPassages: ["Amos 1-2. Judgement on the nations (then Israel)", "Amos 3:7. God reveals plans to His prophets", "Amos 4:12. 'Prepare to meet your God'", "Amos 5:21-24. God rejects worship without justice", "Amos 9:11-15. Future restoration of David's tent"], connections: "Martin Luther King Jr. quoted Amos 5:24 in his 'I Have a Dream' speech. James quotes Amos 9:11-12 at the Jerusalem Council (Acts 15:16-17).", bestFor: "Social justice, prophetic courage, aligning worship with ethics" } },
  { id: 31, name: "Obadiah", chapters: 1, author: "Obadiah", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "The shortest book in the Old Testament. a single chapter prophecy against Edom, Israel's arrogant neighbour who gloated over Jerusalem's fall.", tags: ["Judgement", "Pride"], studyGuide: { keyPassages: ["Obadiah 1:3-4. 'The pride of your heart has deceived you'", "Obadiah 1:10-14. Edom's crimes against Judah", "Obadiah 1:15. 'As you have done, it will be done to you'", "Obadiah 1:21. 'The kingdom will be the Lord's'"], connections: "Edom descended from Esau (Genesis 25-27), making this a family rivalry spanning centuries. The Herods of Jesus' day were Idumean (Edomite).", bestFor: "The danger of pride, consequences of schadenfreude, God defends the vulnerable" } },
  { id: 32, name: "Jonah", chapters: 4, author: "Jonah", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "The reluctant prophet runs from God, gets swallowed by a great fish, preaches to Israel's worst enemy. and then gets angry when God shows mercy.", tags: ["Mercy", "Obedience", "Great fish"], studyGuide: { keyPassages: ["Jonah 1. Running from God", "Jonah 2. Prayer from the belly of the fish", "Jonah 3. Nineveh repents", "Jonah 4. Jonah angry at God's mercy"], connections: "Jesus calls Jonah a sign of His own death and resurrection. three days in the fish, three days in the tomb (Matthew 12:39-41).", bestFor: "God's heart for all people, confronting prejudice, running from God's call" } },
  { id: 33, name: "Micah", chapters: 7, author: "Micah", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "A small-town prophet takes on corrupt leaders. Micah distils the entire Old Testament into one verse, prophesies Bethlehem as the Messiah's birthplace, and ends with a stunning picture of God's forgiveness.", keyVerse: "He has shown you, O mortal, what is good. And what does the Lord require of you? To act justly and to love mercy and to walk humbly with your God.. Micah 6:8", tags: ["Justice", "Mercy", "Humility"], studyGuide: { keyPassages: ["Micah 4:1-5. Swords into ploughshares", "Micah 5:2. Bethlehem prophecy (quoted at Jesus' birth)", "Micah 6:8. The Lord's requirements", "Micah 7:18-19. 'Who is a God like you, who pardons sin?'"], connections: "Micah 5:2 told the magi exactly where Jesus would be born (Matthew 2:5-6). Micah 6:8 is the most concise summary of what God wants from His people.", bestFor: "What God requires, social justice, understanding the Messiah's origins" } },
  { id: 34, name: "Nahum", chapters: 3, author: "Nahum", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "The sequel to Jonah. but this time Nineveh has returned to brutality and won't repent. God's patience has a limit. Nahum pronounces Nineveh's fall.", tags: ["Judgement", "Nineveh"], studyGuide: { keyPassages: ["Nahum 1:2-8. God's character: slow to anger but will not leave the guilty unpunished", "Nahum 1:7. 'The Lord is good, a refuge in times of trouble'", "Nahum 2-3. The graphic fall of Nineveh"], connections: "Read alongside Jonah, Nahum shows that repentance can be temporary. and God's patience, though vast, is not infinite. The tension between mercy and justice is resolved at the cross.", bestFor: "Understanding God's justice alongside His mercy, the reality of judgement" } },
  { id: 35, name: "Habakkuk", chapters: 3, author: "Habakkuk", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "The prophet who argued with God. Habakkuk asks why evil goes unpunished, then is shocked when God's answer is even harder to accept. Ends with a stunning declaration of faith.", keyVerse: "The righteous person will live by his faithfulness.. Habakkuk 2:4", tags: ["Doubt", "Faith", "Hard questions"], studyGuide: { keyPassages: ["Habakkuk 1:2-4. 'How long, Lord, must I call for help?'", "Habakkuk 1:12-2:1. Habakkuk's second complaint", "Habakkuk 2:4. 'The righteous will live by faith'", "Habakkuk 2:14. The earth filled with God's glory", "Habakkuk 3:17-19. 'Yet I will rejoice in the Lord'"], connections: "Habakkuk 2:4 is quoted three times in the New Testament (Romans 1:17, Galatians 3:11, Hebrews 10:38). it became the spark of the Reformation.", bestFor: "Wrestling with doubt, faith in dark times, honest dialogue with God" } },
  { id: 36, name: "Zephaniah", chapters: 3, author: "Zephaniah", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "Begins with the most terrifying description of the Day of the Lord in all the prophets, then pivots to one of the most tender pictures of God's love. He sings over His people with joy.", keyVerse: "The Lord your God is with you, the Mighty Warrior who saves. He will take great delight in you; in his love he will no longer rebuke you, but will rejoice over you with singing.. Zephaniah 3:17", tags: ["Day of the Lord", "Restoration"], studyGuide: { keyPassages: ["Zephaniah 1:14-18. The great Day of the Lord", "Zephaniah 2:3. 'Seek the Lord, all you humble of the land'", "Zephaniah 3:9-13. A purified remnant", "Zephaniah 3:17. God rejoices over you with singing"], connections: "Zephaniah 3:17 is one of the most intimate verses in the Old Testament. God singing over His people like a parent over a child.", bestFor: "Experiencing God's delight, understanding judgement and mercy together, the tender heart of God" } },
  { id: 37, name: "Haggai", chapters: 2, author: "Haggai", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "After returning from exile, the people build nice houses but leave God's temple in ruins. Haggai's blunt message: get your priorities straight.", tags: ["Priorities", "Temple", "Obedience"], studyGuide: { keyPassages: ["Haggai 1:4-6. 'You have planted much, but harvested little'", "Haggai 1:7-8. 'Give careful thought to your ways'", "Haggai 2:6-9. 'The glory of this house will be greater'"], connections: "Haggai's challenge echoes Jesus' teaching in Matthew 6:33 ('Seek first the kingdom'). The promise that the latter temple's glory will exceed the former is fulfilled when Jesus walks through its courts.", bestFor: "Examining priorities, first things first, obedience and God's blessing" } },
  { id: 38, name: "Zechariah", chapters: 14, author: "Zechariah", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "The most Messianic of the minor prophets. Eight night visions encourage the returned exiles, while later chapters prophesy Christ's triumphal entry, betrayal for thirty silver coins, and His return in glory.", tags: ["Messiah", "Visions", "Hope"], studyGuide: { keyPassages: ["Zechariah 3. Joshua the high priest cleansed", "Zechariah 4:6. 'Not by might nor by power, but by my Spirit'", "Zechariah 9:9. The king comes on a donkey (Palm Sunday)", "Zechariah 11:12-13. Thirty pieces of silver", "Zechariah 12:10. 'They will look on me, the one they have pierced'"], connections: "More Zechariah prophecies are fulfilled in Passion Week than from any other prophet: triumphal entry, thirty pieces of silver, the pierced one, the shepherd struck.", bestFor: "Messianic prophecy, understanding Passion Week, encouragement for rebuilders" } },
  { id: 39, name: "Malachi", chapters: 4, author: "Malachi", testament: "old", genre: "minor-prophets", genreLabel: "Minor Prophets", description: "The last voice of the Old Testament before 400 years of prophetic silence. God confronts a cynical, half-hearted people. Ends with the promise of Elijah's return. fulfilled in John the Baptist.", tags: ["Faithfulness", "Tithing", "Coming messenger"], studyGuide: { keyPassages: ["Malachi 1:6-14. Offering God the leftovers", "Malachi 2:16. God's view of broken covenants", "Malachi 3:1. 'I will send my messenger'", "Malachi 3:6-12. Tithing and God's challenge to test Him", "Malachi 4:5-6. Elijah will come"], connections: "Malachi 3:1 is quoted by Mark to introduce John the Baptist (Mark 1:2). After Malachi, 400 years of silence until an angel appears to Zechariah in Luke 1.", bestFor: "Wholehearted worship, generosity, understanding the gap between the testaments" } },
  // Deuterocanonical books (included in Catholic and Orthodox Bibles)
  { id: 40, name: "Tobit", chapters: 14, author: "Unknown", testament: "old", genre: "deuterocanonical", genreLabel: "Deuterocanonical", description: "A faithful Israelite in exile whose son Tobias goes on an adventure guided by the angel Raphael. A story about prayer, marriage, and God working behind the scenes.", tags: ["Angel", "Prayer", "Faithfulness", "Family"], studyGuide: { keyPassages: ["Tobit 4:5-11 - Tobit's instructions to his son", "Tobit 8:5-7 - Tobias and Sarah's wedding prayer", "Tobit 12:6-10 - Raphael reveals himself"], connections: "Tobit's themes of faithful prayer, angelic intervention, and God's hidden hand echo Esther and Daniel.", bestFor: "Prayer life, trusting God's unseen work, family devotion" } },
  { id: 41, name: "Judith", chapters: 16, author: "Unknown", testament: "old", genre: "deuterocanonical", genreLabel: "Deuterocanonical", description: "A brave widow saves her people by outsmarting an enemy general. Courage and faith against impossible odds.", tags: ["Courage", "Deliverance", "Faith", "Heroine"], studyGuide: { keyPassages: ["Judith 8:11-27 - Judith challenges the elders", "Judith 13:1-10 - Judith's bold act", "Judith 16:1-17 - Judith's victory hymn"], connections: "Judith stands alongside Deborah, Jael, and Esther as women who delivered God's people through courage and cunning.", bestFor: "Courage under pressure, women in Scripture, trusting God in crisis" } },
  { id: 42, name: "Wisdom of Solomon", chapters: 19, author: "Unknown", testament: "old", genre: "deuterocanonical", genreLabel: "Deuterocanonical", description: "A meditation on wisdom, justice, and God's care for His people through history. Written in Solomon's style, rich with insight about the afterlife and God's character.", tags: ["Wisdom", "Justice", "Immortality", "Righteousness"], studyGuide: { keyPassages: ["Wisdom 1:1-15 - Seek righteousness", "Wisdom 3:1-9 - The souls of the righteous are in God's hand", "Wisdom 7:22-8:1 - Wisdom described in glowing terms"], connections: "The Wisdom of Solomon deeply influenced early Christian theology about immortality and God's justice. Paul echoes several of its themes in Romans.", bestFor: "Exploring wisdom literature, questions about the afterlife, God's justice" } },
  { id: 43, name: "Sirach", chapters: 51, author: "Ben Sira", testament: "old", genre: "deuterocanonical", genreLabel: "Deuterocanonical", description: "Practical wisdom for everyday life covering friendship, money, speech, and the fear of God. Think Proverbs but with more detail and structure.", tags: ["Wisdom", "Practical", "Fear of God", "Ethics"], studyGuide: { keyPassages: ["Sirach 2:1-11 - Preparing for trials", "Sirach 6:14-17 - On true friendship", "Sirach 38:1-15 - Honouring physicians"], connections: "Sirach bridges the wisdom tradition of Proverbs and the practical teaching of James. Early Christians quoted it frequently.", bestFor: "Daily wisdom, friendships, practical ethics, character formation" } },
  { id: 44, name: "Baruch", chapters: 6, author: "Baruch", testament: "old", genre: "deuterocanonical", genreLabel: "Deuterocanonical", description: "Jeremiah's scribe writes from exile, calling the people to repentance and hope. Includes a letter warning against idol worship.", tags: ["Exile", "Repentance", "Hope", "Idolatry"], studyGuide: { keyPassages: ["Baruch 3:9-4:4 - A hymn to wisdom", "Baruch 4:5-29 - Words of encouragement to exiles", "Baruch 6 - The Letter of Jeremiah against idols"], connections: "Baruch extends the themes of Jeremiah into the exile period, offering comfort to a displaced people.", bestFor: "Finding hope in exile, avoiding false gods, the comfort of God's word" } },
  { id: 45, name: "1 Maccabees", chapters: 16, author: "Unknown", testament: "old", genre: "deuterocanonical", genreLabel: "Deuterocanonical", description: "The Maccabean revolt against Greek oppression. A family fights for religious freedom and reclaims the temple. This is the story behind Hanukkah.", tags: ["Revolt", "Courage", "Temple", "Hanukkah", "Freedom"], studyGuide: { keyPassages: ["1 Maccabees 1:41-64 - The desecration of the temple", "1 Maccabees 2:15-28 - Mattathias starts the revolt", "1 Maccabees 4:36-59 - The rededication of the temple"], connections: "Jesus celebrated Hanukkah (John 10:22), the festival established by the events in this book. Understanding the Maccabean period helps make sense of the world Jesus was born into.", bestFor: "The historical gap between the testaments, religious freedom, courage under persecution" } },
  { id: 46, name: "2 Maccabees", chapters: 15, author: "Unknown", testament: "old", genre: "deuterocanonical", genreLabel: "Deuterocanonical", description: "A retelling of the Maccabean struggle with added theological reflection on martyrdom, resurrection, and praying for the dead.", tags: ["Martyrdom", "Resurrection", "Prayer", "Faith", "Courage"], studyGuide: { keyPassages: ["2 Maccabees 6:18-31 - Eleazar's martyrdom", "2 Maccabees 7 - The mother and her seven sons", "2 Maccabees 12:38-45 - Prayer for the dead"], connections: "The martyrdom stories in 2 Maccabees deeply influenced early Christian thinking about persecution and the afterlife. Hebrews 11:35 may reference the events of chapter 7.", bestFor: "Understanding martyrdom, resurrection hope, the roots of Catholic theology" } },
  { id: 47, name: "Matthew", chapters: 28, author: "Matthew", testament: "new", genre: "gospels", genreLabel: "The Gospels", description: "Written for a Jewish audience, Matthew presents Jesus as the long-awaited Messiah-King, the new Moses. Contains the Sermon on the Mount, extensive Old Testament quotations, and the Great Commission.", tags: ["Messiah", "Kingdom", "Sermon on Mount"], studyGuide: { keyPassages: ["Matthew 5-7. The Sermon on the Mount", "Matthew 13. Kingdom parables", "Matthew 16:13-20. Peter's confession: 'You are the Christ'", "Matthew 26-28. Passion and resurrection", "Matthew 28:18-20. The Great Commission"], connections: "Matthew is the bridge between Old and New Testaments. packed with 'this was to fulfil what was spoken through the prophet'. The Sermon on the Mount reinterprets the Law given at Sinai.", bestFor: "First-time Bible readers, understanding Jesus' teaching, connecting Old and New Testaments" } },
  { id: 48, name: "Mark", chapters: 16, author: "Mark", testament: "new", genre: "gospels", genreLabel: "The Gospels", description: "The shortest, fastest, most action-packed Gospel. Mark presents Jesus as the suffering servant. always doing, always moving, heading inexorably toward the cross.", tags: ["Action", "Servant", "Miracles"], studyGuide: { keyPassages: ["Mark 1:1-15. The beginning of the gospel", "Mark 4:35-41. Jesus calms the storm", "Mark 8:34-38. The cost of following Jesus", "Mark 10:45. 'The Son of Man came to serve and give his life'", "Mark 15-16. Crucifixion and resurrection"], connections: "Mark was likely Peter's account, written for Gentiles. Mark 10:45 is the thesis statement of the entire Gospel.", bestFor: "Busy readers wanting the essential Jesus, understanding discipleship, the cost of following Christ" } },
  { id: 49, name: "Luke", chapters: 24, author: "Luke", testament: "new", genre: "gospels", genreLabel: "The Gospels", description: "The most literary and detailed Gospel, written by a physician with compassion for outsiders. women, the poor, Samaritans, sinners. Contains beloved parables found nowhere else.", keyVerse: "For the Son of Man came to seek and to save the lost.. Luke 19:10", tags: ["Compassion", "Parables", "Outsiders"], studyGuide: { keyPassages: ["Luke 1-2. The most detailed nativity account", "Luke 4:16-21. Jesus' mission statement in Nazareth", "Luke 10:25-37. The Good Samaritan", "Luke 15. The lost sheep, coin, and son (Prodigal Son)", "Luke 24. The road to Emmaus"], connections: "Luke-Acts is a two-volume work tracing salvation from Bethlehem to Rome. The Emmaus road scene (24:13-35) models how to read the whole Old Testament as pointing to Jesus.", bestFor: "Understanding God's heart for the lost, social compassion, the fullest life of Jesus" } },
  { id: 50, name: "John", chapters: 21, author: "John", testament: "new", genre: "gospels", genreLabel: "The Gospels", description: "The most theological Gospel. John selects seven signs and seven 'I am' statements to prove that Jesus is the divine Son of God.", keyVerse: "In the beginning was the Word, and the Word was with God, and the Word was God.. John 1:1", tags: ["Theology", "I Am statements", "Belief", "Signs"], studyGuide: { keyPassages: ["John 1:1-18. The Word became flesh", "John 3:1-21. Nicodemus and being born again", "John 4. The Samaritan woman at the well", "John 14-17. The Upper Room teaching and Jesus' prayer", "John 20:30-31. John's purpose statement"], connections: "John's opening echoes Genesis 1:1, revealing Jesus as the Creator. The seven 'I am' statements connect to God's name revealed to Moses (Exodus 3:14).", bestFor: "Deep theology, personal faith, evangelism, understanding who Jesus claimed to be" } },
  { id: 51, name: "Acts", chapters: 28, author: "Luke", testament: "new", genre: "acts", genreLabel: "History", description: "The sequel to Luke's Gospel: the Holy Spirit empowers the apostles and the church explodes from a handful of disciples in Jerusalem to a movement that reaches Rome.", tags: ["Holy Spirit", "Paul", "Peter", "Church growth"], studyGuide: { keyPassages: ["Acts 1:8. Jesus' final words and the mission mandate", "Acts 2. Pentecost and the birth of the church", "Acts 9. Saul's conversion on the Damascus road", "Acts 15. The Jerusalem Council (Gentiles welcomed)", "Acts 17:16-34. Paul at the Areopagus in Athens"], connections: "Acts fulfils Jesus' promise of the Spirit (John 14-16) and Joel's prophecy (Joel 2:28-32). Paul's missionary journeys set the context for all his letters.", bestFor: "Understanding the early church, the Holy Spirit's work, evangelism and mission" } },
  { id: 52, name: "Romans", chapters: 16, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Paul's theological masterpiece: the most systematic explanation of the gospel ever written. Traces the human problem (sin), God's solution (grace through faith), life in the Spirit, and practical Christian living.", tags: ["Gospel", "Justification", "Grace", "Theology"], studyGuide: { keyPassages: ["Romans 1:16-17. The gospel is the power of God", "Romans 3:21-26. Justification by faith", "Romans 5:1-11. Peace with God and hope in suffering", "Romans 8. Life in the Spirit (no condemnation, nothing separates us)", "Romans 12:1-2. Living sacrifices and renewed minds"], connections: "Romans 8 is considered by many the greatest chapter in the Bible. The book shaped Augustine, Luther, Wesley, and Barth. each reading sparked a movement.", bestFor: "Systematic understanding of the gospel, assurance of salvation, theological foundation" } },
  { id: 53, name: "1 Corinthians", chapters: 16, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Paul writes to a gifted but messy church plagued by division, immorality, and theological confusion. Contains the famous 'love chapter' (ch. 13) and resurrection argument (ch. 15).", tags: ["Love chapter", "Spiritual gifts", "Resurrection"], studyGuide: { keyPassages: ["1 Corinthians 1:18-25. The foolishness of the cross", "1 Corinthians 6:19-20. Your body is a temple", "1 Corinthians 12. The body of Christ and spiritual gifts", "1 Corinthians 13. The love chapter", "1 Corinthians 15. The resurrection of the dead"], connections: "The Lord's Supper passage (11:23-26) is the earliest written account. before the Gospels. The love chapter is Paul's answer to the Corinthians' obsession with spiritual gifts.", bestFor: "Church unity, spiritual gifts, love, the reality of resurrection" } },
  { id: 54, name: "2 Corinthians", chapters: 13, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Paul's most personal, vulnerable letter. He reveals the paradox at the heart of Christian ministry: God's power is made perfect in weakness.", keyVerse: "My grace is sufficient for you, for my power is made perfect in weakness.. 2 Corinthians 12:9", tags: ["Weakness", "Suffering", "Ministry"], studyGuide: { keyPassages: ["2 Corinthians 1:3-7. The God of all comfort", "2 Corinthians 4:7-18. Treasure in jars of clay", "2 Corinthians 5:17-21. New creation, ministry of reconciliation", "2 Corinthians 9:6-7. God loves a cheerful giver", "2 Corinthians 12:7-10. Paul's thorn and God's sufficient grace"], connections: "2 Corinthians 5:17 ('new creation') echoes Isaiah 65:17 and points forward to Revelation 21:5. The 'treasure in jars of clay' metaphor redefines Christian leadership.", bestFor: "Ministry burnout, finding strength in weakness, generous giving, authentic leadership" } },
  { id: 55, name: "Galatians", chapters: 6, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Paul's angriest letter. a passionate defence of salvation by grace through faith alone, against those trying to add Jewish law requirements.", keyVerse: "It is for freedom that Christ has set us free. Stand firm, then, and do not let yourselves be burdened again by a yoke of slavery.. Galatians 5:1", tags: ["Grace", "Freedom", "Faith vs works"], studyGuide: { keyPassages: ["Galatians 2:15-21. Justified by faith, not by works of the law", "Galatians 3:26-29. All one in Christ Jesus", "Galatians 5:1. Freedom in Christ", "Galatians 5:16-26. The fruit of the Spirit", "Galatians 6:7-10. Sowing and reaping"], connections: "Galatians is Romans in miniature. the same gospel, but written in the heat of battle. The fruit of the Spirit (5:22-23) is the character of Christ formed in believers.", bestFor: "Understanding grace, freedom from legalism, spiritual fruit, the gospel's core" } },
  { id: 56, name: "Ephesians", chapters: 6, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "The richest letter on Christian identity: who you are in Christ (chapters 1-3) and how to live it out (chapters 4-6). Covers unity, spiritual warfare, and the armour of God.", tags: ["Identity", "Unity", "Armour of God"], studyGuide: { keyPassages: ["Ephesians 1:3-14. Every spiritual blessing in Christ", "Ephesians 2:1-10. Saved by grace through faith", "Ephesians 3:14-21. Paul's prayer for power and love", "Ephesians 4:1-6. Unity in the body of Christ", "Ephesians 6:10-20. The full armour of God"], connections: "Ephesians 2:8-9 is the clearest statement of salvation by grace in all of Scripture. The armour of God draws on Isaiah's description of God Himself as warrior (Isaiah 59:17).", bestFor: "Identity in Christ, spiritual warfare, marriage, church unity" } },
  { id: 57, name: "Philippians", chapters: 4, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Paul's 'joy letter', written from prison. Despite chains, he overflows with joy, contentment, and gratitude. Contains the majestic 'Christ hymn'.", keyVerse: "Rejoice in the Lord always. I will say it again: Rejoice!. Philippians 4:4", tags: ["Joy", "Contentment", "Humility"], studyGuide: { keyPassages: ["Philippians 1:21. 'To live is Christ and to die is gain'", "Philippians 2:5-11. The Christ hymn (kenosis)", "Philippians 3:7-14. Knowing Christ above all else", "Philippians 4:4-9. Rejoice, peace, and right thinking", "Philippians 4:11-13. The secret of contentment"], connections: "The Christ hymn (2:5-11) is one of the earliest and most profound Christological statements. Philippians 4:13 is best understood in context: contentment in any circumstance.", bestFor: "Joy in hard times, contentment, humility, keeping perspective" } },
  { id: 58, name: "Colossians", chapters: 4, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Christ is supreme over all creation, all powers, all philosophy, all religion. In Christ, believers have everything they need. they are complete.", tags: ["Christ's supremacy", "Completeness"], studyGuide: { keyPassages: ["Colossians 1:15-20. The supremacy of Christ over all things", "Colossians 2:6-15. Fullness in Christ, disarming of powers", "Colossians 2:16-23. Freedom from religious rules", "Colossians 3:1-17. Putting on the new self"], connections: "Colossians 1:15-20 parallels John 1:1-18 and Hebrews 1:1-4 as a cosmic Christology. Paul's attack on human-made religious rules (2:16-23) is liberating.", bestFor: "Christ's sufficiency, freedom from religious performance, the cosmic Christ" } },
  { id: 59, name: "1 Thessalonians", chapters: 5, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Paul's earliest letter, written to a young church he had to leave too soon. Gives the New Testament's most vivid picture of Christ's return.", tags: ["Christ's return", "Encouragement", "Hope"], studyGuide: { keyPassages: ["1 Thessalonians 1:2-10. A model church", "1 Thessalonians 2:7-12. Paul as gentle parent", "1 Thessalonians 4:13-18. Christ's return and the dead in Christ", "1 Thessalonians 5:1-11. The Day of the Lord", "1 Thessalonians 5:16-18. 'Rejoice always, pray continually'"], connections: "The rapture passage (4:13-18) is the most detailed NT description of Christ's return. The comfort is not escapism but hope. those who have died in Christ are not lost.", bestFor: "Hope for the future, comfort in bereavement, Christ's return, new believers" } },
  { id: 60, name: "2 Thessalonians", chapters: 3, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "A follow-up correcting misunderstandings about Christ's return. Some had stopped working, thinking the end was imminent. Paul urges them to stand firm and stay productive.", tags: ["End times", "Perseverance"], studyGuide: { keyPassages: ["2 Thessalonians 1:5-10. God's righteous judgement", "2 Thessalonians 2:1-12. The man of lawlessness", "2 Thessalonians 2:13-17. Stand firm and hold to the teachings", "2 Thessalonians 3:6-13. Warning against idleness"], connections: "The 'man of lawlessness' connects to Daniel's prophecies and John's antichrist (1 John 2:18). Paul's insistence on work balances end-times expectation with present responsibility.", bestFor: "Balanced view of end times, the value of work, perseverance under persecution" } },
  { id: 61, name: "1 Timothy", chapters: 6, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Paul mentors his young protege Timothy on how to lead the church in Ephesus. dealing with false teachers, selecting leaders, and guarding sound doctrine.", tags: ["Leadership", "Doctrine", "Mentoring"], studyGuide: { keyPassages: ["1 Timothy 1:15. 'Christ Jesus came to save sinners, of whom I am the worst'", "1 Timothy 2:1-8. Prayer for all people", "1 Timothy 3:1-13. Qualifications for leaders", "1 Timothy 4:12. 'Don't let anyone look down on you because you are young'", "1 Timothy 6:6-10. Contentment and the danger of loving money"], connections: "The Pastoral Epistles form Paul's leadership legacy. The leader qualifications in chapter 3 remain the foundation for church governance worldwide.", bestFor: "Church leadership, mentoring younger believers, fighting for sound teaching" } },
  { id: 62, name: "2 Timothy", chapters: 4, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Paul's last letter, written from a Roman dungeon before his execution. A deeply personal charge to Timothy to endure, guard the gospel, and pass it on.", keyVerse: "I have fought the good fight, I have finished the race, I have kept the faith.. 2 Timothy 4:7", tags: ["Endurance", "Final words", "Legacy"], studyGuide: { keyPassages: ["2 Timothy 1:7. 'God gave us a spirit not of fear but of power, love, and self-discipline'", "2 Timothy 2:1-7. A soldier, athlete, and farmer", "2 Timothy 2:15. Rightly handling the word of truth", "2 Timothy 3:16-17. All Scripture is God-breathed", "2 Timothy 4:6-8. Paul's farewell"], connections: "2 Timothy 3:16-17 is the foundational text on Scripture's authority. The 'entrust to faithful people' charge (2:2) is the biblical model for discipleship multiplication.", bestFor: "Passing on faith, endurance in ministry, the authority of Scripture, finishing well" } },
  { id: 63, name: "Titus", chapters: 3, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Paul instructs Titus on establishing healthy churches on Crete. appointing leaders, silencing false teachers, and teaching godly living.", tags: ["Leadership", "Good works", "Character"], studyGuide: { keyPassages: ["Titus 1:5-9. Elder qualifications", "Titus 2:1-10. Teaching for every age and stage", "Titus 2:11-14. Grace teaches us to say no to ungodliness", "Titus 3:3-7. Saved not by works but by God's mercy"], connections: "Titus 2:11-14 is one of the most elegant gospel summaries. grace both saves and transforms. We're not saved by works, but saved for works (cf. Ephesians 2:8-10).", bestFor: "Practical Christian living, grace-motivated obedience, church planting" } },
  { id: 64, name: "Philemon", chapters: 1, author: "Paul", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "A short, personal letter asking Philemon to welcome back his runaway slave Onesimus. now a Christian. as a brother.", tags: ["Reconciliation", "Forgiveness", "Equality"], studyGuide: { keyPassages: ["Philemon 1:10-12. Paul appeals for Onesimus", "Philemon 1:15-16. 'No longer as a slave, but as a dear brother'", "Philemon 1:17-19. 'Charge it to me' (substitution language)", "Philemon 1:21. Paul's confidence in Philemon's response"], connections: "Paul's 'charge it to me' echoes Christ's substitution. The letter plants a seed that would eventually undermine slavery (cf. Galatians 3:28).", bestFor: "Forgiveness, reconciliation, the gospel's social implications, persuasion" } },
  { id: 65, name: "Hebrews", chapters: 13, author: "Unknown", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "A brilliant sermon arguing that Jesus is better than everything in the old covenant. better than angels, Moses, the priesthood, the sacrifices, the tabernacle. Chapter 11's 'hall of faith' is one of Scripture's most inspiring passages.", tags: ["Christ's supremacy", "Faith hall of fame", "New covenant"], studyGuide: { keyPassages: ["Hebrews 1:1-4. God has spoken through His Son", "Hebrews 4:14-16. Jesus our great high priest", "Hebrews 10:19-25. Confidence to enter the holy place", "Hebrews 11. The hall of faith", "Hebrews 12:1-3. The race set before us"], connections: "Hebrews is the New Testament's commentary on Leviticus. The 'better' theme runs throughout: better covenant, better promises, better sacrifice, better country.", bestFor: "Understanding how Christ fulfils the Old Testament, perseverance, mature theology" } },
  { id: 66, name: "James", chapters: 5, author: "James", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "The most practical book in the New Testament. rapid-fire wisdom on speech, wealth, patience, prayer, and living out faith. 'Faith without works is dead.'", tags: ["Practical faith", "Works", "Speech", "Wisdom"], studyGuide: { keyPassages: ["James 1:2-4. Joy in trials", "James 1:22. 'Be doers of the word, not hearers only'", "James 2:14-26. Faith without works is dead", "James 3:1-12. The power of the tongue", "James 5:13-16. The prayer of faith"], connections: "James reads like a New Testament Proverbs. His teaching on faith and works complements Paul: Paul says we're justified by faith, James says genuine faith produces works.", bestFor: "Practical Christian living, taming the tongue, integrating faith and action" } },
  { id: 67, name: "1 Peter", chapters: 5, author: "Peter", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Written to scattered, persecuted Christians, Peter encourages them to find hope through Christ's resurrection. Suffering is real, but it refines faith like fire purifies gold.", tags: ["Suffering", "Hope", "Holiness"], studyGuide: { keyPassages: ["1 Peter 1:3-9. A living hope through the resurrection", "1 Peter 2:9-10. A chosen people, a royal priesthood", "1 Peter 2:21-25. Following Christ's example in suffering", "1 Peter 3:15. Always be prepared to give an answer", "1 Peter 5:6-7. Cast all your anxiety on Him"], connections: "Peter's language of 'exiles and strangers' echoes the Old Testament patriarchs. His teaching on suffering draws directly from Isaiah 53.", bestFor: "Suffering well, identity as God's people, apologetics, hope under pressure" } },
  { id: 68, name: "2 Peter", chapters: 3, author: "Peter", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Peter's final letter before his martyrdom. He warns against false teachers and addresses scoffers who mock Christ's delayed return. God's 'delay' is patience, not absence.", keyVerse: "With the Lord a day is like a thousand years, and a thousand years are like a day.. 2 Peter 3:8", tags: ["False teachers", "God's patience", "Return of Christ"], studyGuide: { keyPassages: ["2 Peter 1:3-11. Everything needed for life and godliness", "2 Peter 1:16-21. Peter's eyewitness testimony and Scripture's reliability", "2 Peter 2. Warning against false teachers", "2 Peter 3:8-13. The Day of the Lord will come"], connections: "Peter's eyewitness account of the Transfiguration (1:16-18) corroborates Matthew 17. His warning parallels Jude.", bestFor: "Discernment, spiritual growth, patience with God's timing, defending the faith" } },
  { id: 69, name: "1 John", chapters: 5, author: "John", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Written by the elderly apostle John to assure believers of their salvation. Built around three tests of genuine faith: right belief about Jesus, obedience, and love. 'God is love' is its heartbeat.", tags: ["Love", "Assurance", "Truth"], studyGuide: { keyPassages: ["1 John 1:5-10. Walking in the light and confession", "1 John 2:15-17. Do not love the world", "1 John 3:1. 'See what great love the Father has lavished on us'", "1 John 4:7-21. God is love", "1 John 5:11-13. Assurance of eternal life"], connections: "1 John reads like a pastoral application of John's Gospel. the same themes in a different key. 'God is love' (4:8, 16) is grounded in the cross (4:10).", bestFor: "Assurance of salvation, understanding God's love, dealing with sin and confession" } },
  { id: 70, name: "2 John", chapters: 1, author: "John", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "A brief letter urging believers to walk in truth and love while guarding against false teachers who deny Christ came in the flesh.", tags: ["Truth", "Love", "Discernment"], studyGuide: { keyPassages: ["2 John 1:4-6. Walking in truth and the command to love", "2 John 1:7-9. Warning against deceivers", "2 John 1:10-11. Boundaries with false teachers"], connections: "2 John applies the teachings of 1 John in a specific pastoral situation. The command in verse 5 traces back to Jesus' 'new commandment' (John 13:34).", bestFor: "Balancing truth and love, discernment, protecting the community of faith" } },
  { id: 71, name: "3 John", chapters: 1, author: "John", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "The shortest book in the Bible. John commends Gaius for his hospitality, confronts the controlling Diotrephes, and praises faithful Demetrius. A snapshot of real church dynamics.", tags: ["Hospitality", "Church life", "Leadership"], studyGuide: { keyPassages: ["3 John 1:2-4. Walking in truth brings John joy", "3 John 1:5-8. Gaius' hospitality commended", "3 John 1:9-10. Diotrephes' toxic leadership rebuked", "3 John 1:11. 'Do not imitate what is evil but what is good'"], connections: "3 John provides a real-world case study of truth-and-love principles. Diotrephes is a warning against authoritarian leadership. contrasting with Jesus' servant model (Mark 10:42-45).", bestFor: "Healthy church relationships, hospitality, recognising good and bad leadership" } },
  { id: 72, name: "Jude", chapters: 1, author: "Jude", testament: "new", genre: "letters", genreLabel: "Letters (Epistles)", description: "Jude, Jesus' brother, writes an urgent appeal to 'contend for the faith' against false teachers. Concludes with one of the Bible's most beloved benedictions.", keyVerse: "To him who is able to keep you from stumbling and to present you before his glorious presence without fault and with great joy.. Jude 1:24", tags: ["Contending", "False teachers", "Benediction"], studyGuide: { keyPassages: ["Jude 1:3. 'Contend for the faith'", "Jude 1:5-7. Three Old Testament warnings", "Jude 1:20-23. Building yourselves up, showing mercy", "Jude 1:24-25. The great benediction"], connections: "Jude shares significant content with 2 Peter 2. The closing benediction (vv. 24-25) is one of the most frequently used doxologies in Christian worship.", bestFor: "Defending the faith, recognising false teaching, confidence in God's keeping power" } },
  { id: 73, name: "Revelation", chapters: 22, author: "John", testament: "new", genre: "apocalyptic", genreLabel: "Apocalyptic", description: "The Bible's grand finale. Jesus reveals the end of the story: the defeat of evil, the return of the King, the final judgement, and the new heaven and earth where God dwells with His people forever.", keyVerse: "He who was seated on the throne said, 'I am making everything new!'. Revelation 21:5", tags: ["End times", "Victory", "New creation", "Worship"], studyGuide: { keyPassages: ["Revelation 1:9-20. The risen Christ revealed", "Revelation 4-5. The throne room of heaven", "Revelation 12. The woman, the dragon, and the war", "Revelation 19:11-16. The return of the King", "Revelation 21:1-22:5. New heaven, new earth, no more tears"], connections: "Revelation draws on nearly every Old Testament book. The tree of life from Genesis 2 reappears in Revelation 22, and the curse of Genesis 3 is finally lifted. The story that began in a garden ends in a garden-city.", bestFor: "The big picture of Scripture, worship, hope for the future, understanding symbolism" } },
];
